import{_ as l,o as i,c as t,ae as e}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"企业级全栈 AI 助手系统设计：从聊天界面到可观测服务","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/chatbot-project.md","filePath":"ai-tutorial/chatbot-project.md"}'),s={name:"ai-tutorial/chatbot-project.md"};function n(o,a,r,h,p,d){return i(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="企业级全栈-ai-助手系统设计-从聊天界面到可观测服务" tabindex="-1">企业级全栈 AI 助手系统设计：从聊天界面到可观测服务 <a class="header-anchor" href="#企业级全栈-ai-助手系统设计-从聊天界面到可观测服务" aria-label="Permalink to &quot;企业级全栈 AI 助手系统设计：从聊天界面到可观测服务&quot;">​</a></h1><blockquote><p>“做一个公司内部 AI 助手”这句话，最迷惑人的地方在于它听起来太轻了，像是下周就能顺手做完的小需求。 但只要真的有人开始用，事情会立刻变重：流式体验、会话状态、RAG、工具调用、权限、安全、审计、观测会一下子全部扑上来。很多 Demo 不是做不出来，而是做出来之后才发现自己其实只完成了最容易的那 20%。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章覆盖什么</p><ul><li>一个企业级 AI 助手的核心需求分解</li><li>前端流式体验、后端编排、RAG/Tool 路由如何协同</li><li>会话状态、权限审计、观测与降级策略如何设计</li><li>从 Demo 到生产的演进路径应该怎么走</li></ul></div><h2 id="_1-先定义系统边界-而不是先选模型" tabindex="-1">1. 先定义系统边界，而不是先选模型 <a class="header-anchor" href="#_1-先定义系统边界-而不是先选模型" aria-label="Permalink to &quot;1. 先定义系统边界，而不是先选模型&quot;">​</a></h2><p>企业内部助手最常见的需求通常混在一起：</p><ul><li>问答：查询制度、合同、流程、技术文档</li><li>检索：从知识库或业务系统找到事实</li><li>操作：创建工单、发通知、调用内部接口</li><li>协作：把结果以摘要、报告、待办形式回传给用户</li></ul><p>如果一开始就把它当成“一个聊天框 + 一个模型”，后面会遇到三个问题：</p><ol><li>无法区分“需要回答”还是“需要执行”</li><li>无法明确哪些数据能看、哪些动作能做</li><li>无法定位是模型问题、检索问题还是系统问题</li></ol><p>因此更推荐先按职责把系统拆开。</p><h2 id="_2-推荐的整体架构" tabindex="-1">2. 推荐的整体架构 <a class="header-anchor" href="#_2-推荐的整体架构" aria-label="Permalink to &quot;2. 推荐的整体架构&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    UI[&quot;Web / IM 前端&quot;] --&gt; GW[&quot;API Gateway&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    GW --&gt; ORCH[&quot;Orchestrator 编排层&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ORCH --&gt; LLM[&quot;LLM 网关&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ORCH --&gt; RAG[&quot;RAG 检索层&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ORCH --&gt; TOOL[&quot;工具执行层&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ORCH --&gt; STATE[&quot;会话与任务状态&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ORCH --&gt; OBS[&quot;日志 / Trace / 指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    RAG --&gt; KB[&quot;文档库 / 向量库 / 检索索引&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TOOL --&gt; SYS[&quot;内部业务系统&quot;]</span></span></code></pre></div><p>这套拆分的好处是：</p><ul><li>前端只关心交互与流式展示</li><li>编排层负责判断这次请求该走哪条路线</li><li>RAG 层和工具层可以独立演进</li><li>观测与权限不依赖模型自身能力</li></ul><h2 id="_3-前端体验-为什么流式响应是刚需" tabindex="-1">3. 前端体验：为什么流式响应是刚需 <a class="header-anchor" href="#_3-前端体验-为什么流式响应是刚需" aria-label="Permalink to &quot;3. 前端体验：为什么流式响应是刚需&quot;">​</a></h2><p>用户对 AI 产品的第一印象，往往不是“答案多专业”，而是“系统是不是卡住了”。对长回答场景来说，流式响应几乎是必选项。</p><h3 id="_3-1-建议的前端交互" tabindex="-1">3.1 建议的前端交互 <a class="header-anchor" href="#_3-1-建议的前端交互" aria-label="Permalink to &quot;3.1 建议的前端交互&quot;">​</a></h3><ul><li>首字尽快出现，降低等待焦虑</li><li>工具执行过程有阶段反馈，如“正在检索制度文档”“正在查询工单系统”</li><li>支持中断生成与重新提问</li><li>工具型回答和问答型回答使用不同 UI 展示</li></ul><h3 id="_3-2-前端不是只渲染文本" tabindex="-1">3.2 前端不是只渲染文本 <a class="header-anchor" href="#_3-2-前端不是只渲染文本" aria-label="Permalink to &quot;3.2 前端不是只渲染文本&quot;">​</a></h3><p>当系统走了 RAG 或工具调用路径，前端可以适度暴露过程信息：</p><ul><li>引用了哪些资料</li><li>是否执行了哪个工具</li><li>当前结果是草稿、最终结论还是待审批动作</li></ul><p>这会明显提升用户信任感，也有助于排查问题。</p><h2 id="_4-后端编排层-真正的大脑不在模型-而在路由" tabindex="-1">4. 后端编排层：真正的大脑不在模型，而在路由 <a class="header-anchor" href="#_4-后端编排层-真正的大脑不在模型-而在路由" aria-label="Permalink to &quot;4. 后端编排层：真正的大脑不在模型，而在路由&quot;">​</a></h2><p>同一句用户输入，可能走完全不同的处理路径：</p><ul><li>纯聊天：直接问模型</li><li>知识问答：走 RAG</li><li>操作请求：走 Tool Use</li><li>混合请求：先检索，再调工具，最后生成答案</li></ul><p>这意味着后端需要一个显式编排层，而不是简单把所有输入都转发给模型。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;用户请求&quot;] --&gt; B{&quot;请求类型判定&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|闲聊/泛问答| C[&quot;直接模型生成&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|知识查询| D[&quot;RAG 检索&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|操作请求| E[&quot;工具调用&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt;|复杂任务| F[&quot;多步编排&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; G[&quot;组装上下文&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; H[&quot;执行并回流结果&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; H</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; I[&quot;最终生成&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I</span></span></code></pre></div><h3 id="_4-1-路由判定要回答的不是-像不像-agent" tabindex="-1">4.1 路由判定要回答的不是“像不像 Agent” <a class="header-anchor" href="#_4-1-路由判定要回答的不是-像不像-agent" aria-label="Permalink to &quot;4.1 路由判定要回答的不是“像不像 Agent”&quot;">​</a></h3><p>更实用的判定标准是：</p><ul><li>这个问题的答案是否依赖企业私有知识</li><li>这个问题是否需要访问实时数据</li><li>这个问题是否要产生外部副作用</li></ul><p>只要涉及后两者，就不应该直接把它当成普通聊天。</p><h2 id="_5-会话状态-短对话和长任务不能用同一套模型" tabindex="-1">5. 会话状态：短对话和长任务不能用同一套模型 <a class="header-anchor" href="#_5-会话状态-短对话和长任务不能用同一套模型" aria-label="Permalink to &quot;5. 会话状态：短对话和长任务不能用同一套模型&quot;">​</a></h2><p>企业助手至少要管理两种状态：</p><table tabindex="0"><thead><tr><th>类型</th><th>例子</th><th>建议存储</th></tr></thead><tbody><tr><td>聊天状态</td><td>最近几轮对话、当前语言风格</td><td>Redis / 会话缓存</td></tr><tr><td>任务状态</td><td>当前步骤、工具结果、审批状态</td><td>任务表 / 工作流引擎</td></tr></tbody></table><p>如果把所有状态都塞进 <code>messages</code>：</p><ul><li>成本会持续上涨</li><li>长任务无法恢复</li><li>出错后几乎没法排查</li></ul><p>更推荐的做法是：</p><ul><li>会话层只保留与表达相关的上下文</li><li>任务层单独记录流程状态和关键中间结果</li></ul><h2 id="_6-rag-与-tool-的分工" tabindex="-1">6. RAG 与 Tool 的分工 <a class="header-anchor" href="#_6-rag-与-tool-的分工" aria-label="Permalink to &quot;6. RAG 与 Tool 的分工&quot;">​</a></h2><p>很多项目最大的问题，是把 RAG 和 Tool Use 混成一团。其实两者职责很不同：</p><h3 id="_6-1-rag-负责-补事实" tabindex="-1">6.1 RAG 负责“补事实” <a class="header-anchor" href="#_6-1-rag-负责-补事实" aria-label="Permalink to &quot;6.1 RAG 负责“补事实”&quot;">​</a></h3><p>适合场景：</p><ul><li>查制度</li><li>查合同条款</li><li>查知识文档</li><li>给出基于资料的解释</li></ul><h3 id="_6-2-tool-负责-取实时数据-做动作" tabindex="-1">6.2 Tool 负责“取实时数据 / 做动作” <a class="header-anchor" href="#_6-2-tool-负责-取实时数据-做动作" aria-label="Permalink to &quot;6.2 Tool 负责“取实时数据 / 做动作”&quot;">​</a></h3><p>适合场景：</p><ul><li>查当前余额</li><li>查最新工单状态</li><li>创建任务</li><li>更新业务记录</li></ul><p>一个实用的系统原则是：</p><ul><li><strong>静态知识优先走 RAG</strong></li><li><strong>实时状态优先走工具</strong></li><li><strong>涉及副作用一定走工具</strong></li></ul><h2 id="_7-权限、安全与审计-生产环境的硬要求" tabindex="-1">7. 权限、安全与审计：生产环境的硬要求 <a class="header-anchor" href="#_7-权限、安全与审计-生产环境的硬要求" aria-label="Permalink to &quot;7. 权限、安全与审计：生产环境的硬要求&quot;">​</a></h2><p>企业助手一旦接入业务系统，安全问题会立刻从“内容风险”变成“操作风险”。</p><p>至少要有三层防线：</p><h3 id="_7-1-数据权限" tabindex="-1">7.1 数据权限 <a class="header-anchor" href="#_7-1-数据权限" aria-label="Permalink to &quot;7.1 数据权限&quot;">​</a></h3><ul><li>当前用户能看到哪些知识</li><li>当前用户能查询哪些业务数据</li><li>当前 Agent 被允许调用哪些工具</li></ul><h3 id="_7-2-动作权限" tabindex="-1">7.2 动作权限 <a class="header-anchor" href="#_7-2-动作权限" aria-label="Permalink to &quot;7.2 动作权限&quot;">​</a></h3><ul><li>哪些动作可以自动执行</li><li>哪些动作需要审批</li><li>哪些动作禁止开放给模型</li></ul><h3 id="_7-3-审计追踪" tabindex="-1">7.3 审计追踪 <a class="header-anchor" href="#_7-3-审计追踪" aria-label="Permalink to &quot;7.3 审计追踪&quot;">​</a></h3><p>每次请求至少记录：</p><ul><li>用户输入摘要</li><li>路由结果</li><li>引用文档或工具调用记录</li><li>最终回答</li><li>Token 成本与延迟</li></ul><p>没有审计的 AI 助手，很难进入真正的企业环境。</p><h2 id="_8-观测设计-你需要知道系统到底慢在哪里" tabindex="-1">8. 观测设计：你需要知道系统到底慢在哪里 <a class="header-anchor" href="#_8-观测设计-你需要知道系统到底慢在哪里" aria-label="Permalink to &quot;8. 观测设计：你需要知道系统到底慢在哪里&quot;">​</a></h2><p>AI 应用的延迟通常来自多个阶段：</p><ul><li>首次排队</li><li>检索耗时</li><li>模型首字时间</li><li>工具调用耗时</li><li>最终生成耗时</li></ul><p>建议至少建立以下指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>作用</th></tr></thead><tbody><tr><td>TTFT（首字时间）</td><td>观察用户体感延迟</td></tr><tr><td>检索耗时</td><td>判断知识库瓶颈</td></tr><tr><td>工具成功率</td><td>判断外部系统稳定性</td></tr><tr><td>每请求 Token 成本</td><td>判断成本结构</td></tr><tr><td>引用命中率</td><td>判断 RAG 质量</td></tr></tbody></table><p>同时用 Trace 记录一条请求完整经过了哪些环节，后期排查问题会非常关键。</p><h2 id="_9-从-demo-到生产-建议分三步走" tabindex="-1">9. 从 Demo 到生产，建议分三步走 <a class="header-anchor" href="#_9-从-demo-到生产-建议分三步走" aria-label="Permalink to &quot;9. 从 Demo 到生产，建议分三步走&quot;">​</a></h2><h3 id="第一步-只做问答闭环" tabindex="-1">第一步：只做问答闭环 <a class="header-anchor" href="#第一步-只做问答闭环" aria-label="Permalink to &quot;第一步：只做问答闭环&quot;">​</a></h3><ul><li>聊天前端</li><li>基础会话状态</li><li>模型网关</li><li>少量知识文档</li></ul><p>目标是确认用户问题类型和真实需求。</p><h3 id="第二步-引入-rag-和观测" tabindex="-1">第二步：引入 RAG 和观测 <a class="header-anchor" href="#第二步-引入-rag-和观测" aria-label="Permalink to &quot;第二步：引入 RAG 和观测&quot;">​</a></h3><ul><li>知识切分与索引</li><li>引用展示</li><li>检索评估</li><li>成本与延迟指标</li></ul><p>目标是确认“回答质量是否稳定”。</p><h3 id="第三步-引入工具与审批流" tabindex="-1">第三步：引入工具与审批流 <a class="header-anchor" href="#第三步-引入工具与审批流" aria-label="Permalink to &quot;第三步：引入工具与审批流&quot;">​</a></h3><ul><li>只读工具</li><li>有副作用工具的审批机制</li><li>幂等与状态恢复</li><li>全链路审计</li></ul><p>目标是让助手从“会回答”变成“能协助完成任务”。</p><h2 id="_10-一个常见但错误的做法" tabindex="-1">10. 一个常见但错误的做法 <a class="header-anchor" href="#_10-一个常见但错误的做法" aria-label="Permalink to &quot;10. 一个常见但错误的做法&quot;">​</a></h2><p>很多团队会把“企业助手”设计成一个超大 Prompt：</p><ul><li>让它自己判断要不要查知识库</li><li>让它自己拼接 SQL</li><li>让它自己组织动作</li><li>让它自己决定要不要执行</li></ul><p>这种方案的问题不是“不够优雅”，而是工程边界完全模糊。一旦出错，你无法回答：</p><ul><li>错在知识召回还是模型推理</li><li>为什么执行了这个动作</li><li>有没有越权</li><li>能不能回滚</li></ul><p>真正能落地的系统，一定是把这些责任显式拆开。</p><h2 id="_11-小结" tabindex="-1">11. 小结 <a class="header-anchor" href="#_11-小结" aria-label="Permalink to &quot;11. 小结&quot;">​</a></h2><p>企业级 AI 助手不是“一个会聊天的页面”，而是一套围绕模型组织起来的系统工程：</p><ul><li>前端负责体验与可解释反馈</li><li>编排层负责路径判断与状态推进</li><li>RAG 负责提供静态事实</li><li>Tool 负责访问实时世界</li><li>安全、审计、观测负责把能力关进边界里</li></ul><p>当这些层次明确之后，模型才会真正成为系统能力的一部分，而不是一团难以控制的黑盒。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/function-calling" target="_blank" rel="noreferrer">OpenAI: Function calling</a></li><li><a href="https://platform.openai.com/docs/guides/structured-outputs" target="_blank" rel="noreferrer">OpenAI: Structured outputs</a></li><li><a href="https://docs.anthropic.com/en/docs/agents-and-tools/tool-use/overview" target="_blank" rel="noreferrer">Anthropic: Tool use overview</a></li><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li>延伸阅读：<a href="./rag-intro.html">初探 RAG 架构</a></li></ul>`,86)])])}const k=l(s,[["render",n]]);export{c as __pageData,k as default};
